&lt;ul class=&quot;ak-ul&quot; data-indent-level=&quot;1&quot;&gt;
&lt;li&gt;
&lt;p data-renderer-start-pos=&quot;3007&quot;&gt;Comprehensive health coverage including medical, dental, and vision&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p data-renderer-start-pos=&quot;3078&quot;&gt;401(k) Plan&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p data-renderer-start-pos=&quot;3093&quot;&gt;Equity awards&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p data-renderer-start-pos=&quot;3110&quot;&gt;Flexible time off&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p data-renderer-start-pos=&quot;3131&quot;&gt;Paid parental leave&lt;/p&gt;
&lt;/li&gt;
